def validate_identifier(identifier: str, allowed_list: List[str]) -> bool:
    return identifier in allowed_list

def validate_column(table: str, column: str) -> bool:
    if table not in ALLOWED_COLUMNS:
        return False
    return column in ALLOWED_COLUMNS[table]

def sanitize_value(value: Any) -> Any:
    if isinstance(value, str):
        return value.replace("'", "''")
    return value

def build_where_clause(filters: List[Dict], table: str) -> Tuple[sql.Composed, List]:
    if not filters:
        return sql.SQL(""), []
    
    conditions = []
    params = []
    
    for i, f in enumerate(filters):
        column = f.get('column')
        operator = f.get('operator', '=').upper()
        value = f.get('value')
        logical = f.get('logical', 'AND').upper() if i > 0 else None
        
        if not validate_column(table, column):
            raise ValueError(f"Invalid column: {column} for table: {table}")
        
        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Invalid operator: {operator}")
        
        if logical and logical not in ALLOWED_LOGICAL:
            raise ValueError(f"Invalid logical operator: {logical}")
        
        if i > 0 and logical:
            conditions.append(sql.SQL(f" {logical} "))
        
        if operator in ['IS NULL', 'IS NOT NULL']:
            conditions.append(sql.SQL("{} {}").format(
                sql.Identifier(column),
                sql.SQL(operator)
            ))
        elif operator == 'IN':
            if not isinstance(value, list):
                raise ValueError("Value for IN operator must be a list")
            placeholders = sql.SQL(', ').join([sql.Placeholder()] * len(value))
            conditions.append(sql.SQL("{} IN ({})").format(
                sql.Identifier(column),
                placeholders
            ))
            params.extend(value)
        elif operator == 'LIKE':
            conditions.append(sql.SQL("{} LIKE {}").format(
                sql.Identifier(column),
                sql.Placeholder()
            ))
            params.append(value)
        else:
            conditions.append(sql.SQL("{} {} {}").format(
                sql.Identifier(column),
                sql.SQL(operator),
                sql.Placeholder()
            ))
            params.append(value)
    
    where_clause = sql.SQL("WHERE ") + sql.SQL("").join(conditions)
    return where_clause, params

def build_order_clause(order_by: List[Dict], table: str) -> sql.Composed:
    if not order_by:
        return sql.SQL("")
    
    order_parts = []
    for order in order_by:
        column = order.get('column')
        direction = order.get('direction', 'ASC').upper()
        
        if not validate_column(table, column):
            raise ValueError(f"Invalid column for ordering: {column}")
        
        if direction not in ALLOWED_ORDER:
            raise ValueError(f"Invalid order direction: {direction}")
        
        order_parts.append(sql.SQL("{} {}").format(
            sql.Identifier(column),
            sql.SQL(direction)
        ))
    
    return sql.SQL("ORDER BY ") + sql.SQL(", ").join(order_parts)

