@app.route('/api/query', methods=['POST'])
def dynamic_query():
    try:
        data = request.get_json()
        
        table = data.get('table')
        columns = data.get('columns', ['*'])
        filters = data.get('filters', [])
        order_by = data.get('order_by', [])
        limit = data.get('limit')
        offset = data.get('offset', 0)
        
        if not table:
            return error_response("Table name is required")
        
        if not validate_identifier(table, ALLOWED_TABLES):
            return error_response(f"Table '{table}' is not allowed")
        
        if columns != ['*']:
            for col in columns:
                if not validate_column(table, col):
                    return error_response(f"Column '{col}' is not allowed for table '{table}'")
        
        select_clause = sql.SQL("SELECT ")
        if columns == ['*']:
            select_clause += sql.SQL("*")
        else:
            select_clause += sql.SQL(", ").join([sql.Identifier(col) for col in columns])
        
        from_clause = sql.SQL("FROM {}").format(sql.Identifier(table))
        
        where_clause, params = build_where_clause(filters, table)
        
        order_clause = build_order_clause(order_by, table)
        
        limit_clause = sql.SQL("")
        if limit:
            limit_clause = sql.SQL("LIMIT {} OFFSET {}").format(
                sql.Literal(int(limit)),
                sql.Literal(int(offset))
            )
        
        query = sql.SQL(" ").join(filter(lambda x: x, [
            select_clause,
            from_clause,
            where_clause,
            order_clause,
            limit_clause
        ]))
        
        conn = get_db_connection()
        cursor = conn.cursor(cursor_factory=extras.RealDictCursor)
        
        cursor.execute(query, params)
        results = cursor.fetchall()
        
        cursor.close()
        conn.close()
        
        return jsonify({
            'success': True,
            'data': results,
            'count': len(results)
        })
        
    except ValueError as ve:
        return error_response(str(ve))
    except psycopg2.Error as pe:
        return error_response(f"Database error: {str(pe)}", 500)
    except Exception as e:
        return error_response(f"Internal error: {str(e)}", 500)

